import csv
from pathlib import Path
paths = [Path(r'c:\Users\loganf\Downloads\minidata.csv'), Path(r'c:\Users\loganf\Downloads\minidata (1).csv'), Path(r'c:\Users\loganf\Downloads\minidata (2).csv')]

def load(path):
    raw = path.read_bytes()
    for enc in ('utf-8','utf-8-sig','cp1252','latin-1'):
        try:
            text = raw.decode(enc)
            break
        except UnicodeDecodeError:
            continue
    rows = []
    for row in csv.reader(text.splitlines()):
        if not row or all(not c.strip() for c in row):
            continue
        if len(row) == 5 and row[-1] == '':
            row = row[:-1]
        rows.append(tuple(row))
    return {r[0]: r for r in rows}

loaded = [(p.name, load(p)) for p in paths]
for i in range(len(loaded)-1):
    a_name, a = loaded[i]
    b_name, b = loaded[i+1]
    added = sorted(set(b)-set(a))
    removed = sorted(set(a)-set(b))
    changed = sorted(k for k in set(a)&set(b) if a[k] != b[k])
    print(f'{a_name} -> {b_name}')
    print(' added', len(added), added[:12])
    print(' removed', len(removed), removed[:12])
    print(' changed', len(changed))
    for key in changed[:10]:
        print('  ', key, '::', a[key], '=>', b[key])
    print()
